-- Generated by `losty new @@APP_NAME@@`
-- Generates conf/nginx.conf from conf/tmpl/nginx.conf for the given environment.
-- Run this before starting nginx whenever you change the env or template.
--
-- Usage:
--   luajit gen.lua dev
--   luajit gen.lua prod

local env = arg[1]
assert(env == 'dev' or env == 'prod', 'Usage: luajit gen.lua dev|prod')

local settings = {
   dev = {
		env = 'dev'
      , daemon     = 'off'
      , errorlevel = 'debug'
      , code_cache = 'off'
      , listen     = '8080'
		, certs = ''
		, includes = ''
   }
   , prod = {
		env = 'prod'
      , daemon     = 'on'
      , errorlevel = 'warn'
      , code_cache = 'on'
      , listen = '443 ssl default_server reuseport' -- same ip:port cannot serve http1.1/http2 simultaneously
      , certs = [[
         ssl_certificate certs/@@DOMAIN@@.cer;
         ssl_certificate_key certs/@@DOMAIN@@.key;
      ]]
      , includes = [[
         include ssl.conf;
      ]]
   }
}

local cfg = settings[env]
cfg.domain = '@@DOMAIN@@'  -- baked in by `losty`


local function read(path)
    local f = assert(io.open(path, 'rb'), 'Cannot open ' .. path)
    local t = f:read('*a')
    f:close()
    return t
end

local function write(path, t)
    local f = assert(io.open(path, 'wb'), 'Cannot write ' .. path)
    f:write(t)
    f:close()
end

-- Replace {key} placeholders; leave unknown keys as-is.
local function render(tmpl, data)
    return (tmpl:gsub('{([%w_]+)}', function(k)
        return tostring(data[k] or ('{' .. k .. '}'))
    end))
end

local function interpolate(from, to)
   local tmpl = read(from)
   local out  = render(tmpl, cfg)
   write(to, out)
   io.write('Generated ' .. to .. ' [' .. env .. ']\n')
end

interpolate('_tmpl/nginx.conf_', 'conf/nginx.conf')
interpolate('_tmpl/www.conf_', 'conf/www.conf')
interpolate('_tmpl/config.lua_', 'config.lua')

local port = cfg.listen:match('^(%d+)')
io.write('Visit http://localhost:' .. port .. '\n')
